async fn verify_provenance_at_lock_time(
    &self,
    tv: &ToolVersion,
    opts: &GitBackendOptions<'_>,
    repo: &str,
    api_url: &str,
    asset: &ReleaseAsset,
) -> Result<(Option<ProvenanceType>, Option<GithubAttestationsStatus>)> {
