}

struct TestVerifier {
    artifact_path: PathBuf,
    results: HashMap<String, TestVerification>,
    calls: Arc<Mutex<Vec<String>>>,
}

impl AttestationVerifier for TestVerifier {
    fn verify<'a>(&'a mut self, path: &'a Path) -> VerifyFuture<'a> {
        let key = if path == artifact_path {
            "archive".to_string()
        } else {
            path.file_name().unwrap().to_string_lossy().into_owned()
        };
        self.calls.lock().unwrap().push(key.clone());
        let result = match self.results.remove(&key).unwrap() {
            TestVerification::Verified => Ok(true),
