+type VerifyFuture<'a> = Pin<Box<dyn Future<Output = AttestationResult<bool>> + Send + 'a>>;
+
+trait AttestationVerifier {
+    fn verify<'a>(&'a mut self, path: &'a Path) -> VerifyFuture<'a>;
+}
+
+struct GitHubAttestationVerifier<'a> {
+    owner: &'a str,
+    repo: &'a str,
+    expected_workflow: Option<&'a str>,
+    api_url: Option<&'a str>,
+}
+
+impl AttestationVerifier for GitHubAttestationVerifier<'_> {
+    fn verify<'a>(&'a mut self, path: &'a Path) -> VerifyFuture<'a> {
+        Box::pin(verify_attestation(
+            path,
+            self.owner,
+            self.repo,
+            self.expected_workflow,
+            self.api_url,
+        ))
+    }
+}
+
+/// Verify the release asset itself, falling back to every regular file in an archive only when
+/// GitHub reports that the archive blob has no attestations.
+pub async fn verify_attestation_or_archive_files(
+    artifact_path: &Path,
+    format: crate::file::TarFormat,
+    owner: &str,
+    repo: &str,
+    expected_workflow: Option<&str>,
+    api_url: Option<&str>,
+) -> AttestationResult<bool> {
+    let mut verifier = GitHubAttestationVerifier {
+        owner,
+        repo,
+        expected_workflow,
+        api_url,
+    };
+    verify_attestation_or_archive_files_with(artifact_path, format, &mut verifier).await
+}
+
+async fn verify_attestation_or_archive_files_with(
+    artifact_path: &Path,
+    format: crate::file::TarFormat,
+    verifier: &mut impl AttestationVerifier,
+) -> AttestationResult<bool> {
+    match verifier.verify(artifact_path).await {
+        Ok(verified) => return Ok(verified),
+        Err(AttestationError::NoAttestations) if format.is_archive() => {}
+        Err(e) => return Err(e),
+    }
+
+    let temp_dir = tempfile::tempdir().map_err(AttestationError::Io)?;
+    crate::file::untar(
+        artifact_path,
+        temp_dir.path(),
+        &crate::file::TarOptions::new(format),
+    )
+    .map_err(|e| {
+        AttestationError::Verification(format!(
+            "failed to extract archive for per-file attestation verification: {e}"
+        ))
+    })?;
+
+    let files = archive_regular_files(temp_dir.path())?;
+    if files.is_empty() {
+        return Err(AttestationError::NoAttestations);
+    }
+
+    let mut verified_any = false;
+    let mut unattested = Vec::new();
+    for path in files {
+        match verifier.verify(&path).await {
+            Ok(true) => verified_any = true,
+            Ok(false) => return Ok(false),
+            Err(AttestationError::NoAttestations) => {
+                unattested.push(
+                    path.strip_prefix(temp_dir.path())
+                        .unwrap_or(&path)
+                        .display()
+                        .to_string(),
+                );
+            }
+            Err(e) => return Err(e),
+        }
+    }
+
+    if !verified_any {
+        Err(AttestationError::NoAttestations)
+    } else if unattested.is_empty() {
+        Ok(true)
+    } else {
+        Err(AttestationError::Verification(format!(
+            "archive members without GitHub artifact attestations: {}",
+            unattested.join(", ")
+        )))
+    }
+}
+
+fn archive_regular_files(root: &Path) -> AttestationResult<Vec<PathBuf>> {
+    let mut files = Vec::new();
+    for entry in walkdir::WalkDir::new(root).follow_links(false) {
+        let entry = entry.map_err(|e| {
+            AttestationError::Verification(format!(
+                "failed to inspect extracted archive for attestation verification: {e}"
+            ))
+        })?;
+        let file_type = entry.file_type();
+        if file_type.is_file() {
+            files.push(entry.into_path());
+        } else if !file_type.is_dir() {
+            return Err(AttestationError::Verification(format!(
+                "archive member {} is not a regular file",
+                entry
+                    .path()
+                    .strip_prefix(root)
+                    .unwrap_or(entry.path())
+                    .display()
+            )));
+        }
+    }
+    files.sort();
+    Ok(files)
+}
